def build_suffix_array(s):
    n = len(s)
    if n == 0:
        return []

    sa = list(range(n))
    rank = [ord(c) for c in s]

    L = 1
    while L < n:
        sa.sort(key=lambda i: (rank[i], rank[i + L] if i + L < n else -1))

        new_rank = [0] * n
        new_rank[sa[0]] = 0

        for j in range(1, n):
            current_pair = (rank[sa[j]], rank[sa[j] + L] if sa[j] + L < n else -1)
            prev_pair = (rank[sa[j-1]], rank[sa[j-1] + L] if sa[j-1] + L < n else -1)

            if current_pair == prev_pair:
                new_rank[sa[j]] = new_rank[sa[j-1]]
            else:
                new_rank[sa[j]] = new_rank[sa[j-1]] + 1

        rank = new_rank
        L *= 2

        if rank[sa[-1]] == n - 1:
            break

    return sa
